import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Briefcase, DollarSign, TrendingUp } from "lucide-react"

interface ManagerOverviewProps {
  managedFundsCount: number
  totalAUM: number
}

export function ManagerOverview({ managedFundsCount, totalAUM }: ManagerOverviewProps) {
  const formatCurrency = (value: number) => {
    const crores = value / 10000000
    return `₹${crores.toFixed(2)} Cr`
  }

  return (
    <div className="grid gap-4 md:grid-cols-3">
      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Managed Funds</CardTitle>
          <Briefcase className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{managedFundsCount}</div>
          <p className="mt-1 text-xs text-gray-500">Active mutual funds</p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Total AUM</CardTitle>
          <DollarSign className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{formatCurrency(totalAUM)}</div>
          <p className="mt-1 text-xs text-gray-500">Assets under management</p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Avg. Performance</CardTitle>
          <TrendingUp className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold text-green-600">+12.4%</div>
          <p className="mt-1 text-xs text-gray-500">Last 1 year</p>
        </CardContent>
      </Card>
    </div>
  )
}
